/**
 * MMS Minimap Component
 *
 * Compact navigation overlay showing compressed timeline with PM density heatmap
 * and clickable viewport indicator for canvas navigation.
 *
 * Based on specs/006-user-interface.md Section 6.2 (Application Layout).
 */

import React, { useRef } from 'react';
import { Card } from '@blueprintjs/core';

import { useCanvas, useCanvasData, useFleet } from '../../store';
import type { CanvasSliceState } from '../../store/slices/canvas';
import type { CanvasDataState } from '../../store/slices/canvas';
import type { FleetSliceState } from '../../store/slices/fleet';

/** Minimap dimensions */
const MINIMAP_WIDTH = 240;
const MINIMAP_HEIGHT = 48;
const MINIMAP_PADDING = 4;

/** 10-year horizon constants */
const HORIZON_YEARS = 10;

/** PM density color scale (matches strategic heatmap) */
const DENSITY_COLORS: Record<number, string> = {
  0: 'rgba(240, 249, 255, 0.4)', // No PMs - very light
  1: 'rgba(186, 230, 253, 0.6)', // 1 PM
  2: 'rgba(125, 211, 252, 0.7)', // 2 PMs
  3: 'rgba(56, 189, 248, 0.8)',  // 3 PMs
  4: 'rgba(14, 165, 233, 0.85)', // 4+ PMs - dark blue
};

function getDensityColor(pmCount: number): string {
  if (pmCount <= 0) return DENSITY_COLORS[0];
  if (pmCount <= 1) return DENSITY_COLORS[1];
  if (pmCount <= 2) return DENSITY_COLORS[2];
  if (pmCount <= 3) return DENSITY_COLORS[3];
  return DENSITY_COLORS[4];
}

export interface MinimapProps {
  /** Override visibility (defaults to canvas state) */
  visible?: boolean;
  /** Custom width in pixels */
  width?: number;
  /** Custom height in pixels */
  height?: number;
  /** Callback when viewport is clicked/dragged */
  onNavigate?: (date: string) => void;
}

export function Minimap({
  visible,
  width = MINIMAP_WIDTH,
  height = MINIMAP_HEIGHT,
  onNavigate,
}: MinimapProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
  const { state: canvasDataStateRaw } = useCanvasData();
  const { state: fleetStateRaw } = useFleet();

  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
  const fleetState = fleetStateRaw as unknown as FleetSliceState;

  // Determine visibility from props or canvas state
  const isVisible = visible ?? canvasState.showMinimap;

  if (!isVisible) {
    return null;
  }

  // Calculate timeline range (10 years from first train's start or current year)
  const startYear = canvasDataState.fromYear || new Date().getFullYear();
  const endYear = startYear + HORIZON_YEARS;
  const totalMonths = HORIZON_YEARS * 12;

  // Calculate effective content width (excluding padding)
  const contentWidth = width - MINIMAP_PADDING * 2;
  const monthWidth = contentWidth / totalMonths;

  // Compute monthly PM density from strategic data
  const monthlyDensity: number[] = new Array(totalMonths).fill(0);

  if (canvasDataState.strategicData?.trains) {
    for (const train of canvasDataState.strategicData.trains) {
      for (const yearData of train.years) {
        const yearOffset = yearData.year - startYear;
        if (yearOffset >= 0 && yearOffset < HORIZON_YEARS) {
          // Distribute PM count evenly across 12 months for that year
          const pmPerMonth = Math.ceil(yearData.pmCount / 12);
          for (let m = 0; m < 12; m++) {
            const monthIndex = yearOffset * 12 + m;
            if (monthIndex < totalMonths) {
              monthlyDensity[monthIndex] += pmPerMonth;
            }
          }
        }
      }
    }
  }

  // Normalize density for color mapping (0-4 scale based on train count)
  const trainCount = fleetState.trains?.length || canvasDataState.strategicData?.trains.length || 1;
  const maxDensityPerMonth = trainCount * 2; // ~2 PMs per train per month max

  // Calculate viewport position on minimap
  const viewportStart = new Date(canvasState.viewport.startDate);
  const viewportEnd = new Date(canvasState.viewport.endDate);
  const timelineStart = new Date(startYear, 0, 1);
  const timelineEnd = new Date(endYear, 11, 31);

  const totalDays = (timelineEnd.getTime() - timelineStart.getTime()) / (1000 * 60 * 60 * 24);
  const viewportStartDays = Math.max(0, (viewportStart.getTime() - timelineStart.getTime()) / (1000 * 60 * 60 * 24));
  const viewportEndDays = Math.min(totalDays, (viewportEnd.getTime() - timelineStart.getTime()) / (1000 * 60 * 60 * 24));

  const viewportLeft = MINIMAP_PADDING + (viewportStartDays / totalDays) * contentWidth;
  const viewportWidth = Math.max(8, ((viewportEndDays - viewportStartDays) / totalDays) * contentWidth);

  // Handle click to navigate
  const handleClick = (event: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const clickX = event.clientX - rect.left - MINIMAP_PADDING;
    const clickRatio = Math.max(0, Math.min(1, clickX / contentWidth));

    // Calculate target date from click position
    const clickDays = clickRatio * totalDays;
    const targetDate = new Date(timelineStart.getTime() + clickDays * 24 * 60 * 60 * 1000);
    const targetDateStr = targetDate.toISOString().split('T')[0];

    if (onNavigate) {
      onNavigate(targetDateStr);
    } else {
      canvasActions.setViewport({ startDate: targetDateStr });
    }
  };

  // Render year markers
  const yearMarkers: React.ReactNode[] = [];
  for (let y = 0; y <= HORIZON_YEARS; y += 2) {
    const year = startYear + y;
    const x = MINIMAP_PADDING + (y / HORIZON_YEARS) * contentWidth;
    yearMarkers.push(
      <div
        key={year}
        style={{
          position: 'absolute',
          left: `${x}px`,
          bottom: '2px',
          fontSize: '8px',
          color: 'var(--pt-text-muted)',
          fontFamily: 'monospace',
          transform: 'translateX(-50%)',
          pointerEvents: 'none',
        }}
      >
        {year}
      </div>
    );
  }

  // Render density bars
  const densityBars: React.ReactNode[] = [];
  for (let i = 0; i < totalMonths; i++) {
    const density = monthlyDensity[i];
    const normalizedDensity = Math.min(4, Math.ceil((density / maxDensityPerMonth) * 4));
    const color = getDensityColor(normalizedDensity);

    densityBars.push(
      <div
        key={i}
        style={{
          position: 'absolute',
          left: `${MINIMAP_PADDING + i * monthWidth}px`,
          top: '6px',
          width: `${Math.max(1, monthWidth - 0.5)}px`,
          height: `${height - 20}px`,
          backgroundColor: color,
          borderRadius: '1px',
          pointerEvents: 'none',
        }}
      />
    );
  }

  return (
    <Card
      elevation={1}
      style={{
        padding: 0,
        overflow: 'hidden',
        cursor: 'pointer',
      }}
    >
      <div
        ref={containerRef}
        data-testid="minimap"
        onClick={handleClick}
        style={{
          position: 'relative',
          width: `${width}px`,
          height: `${height}px`,
          backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
        }}
        role="navigation"
        aria-label="Timeline minimap navigation"
        title="Click to navigate to a specific time period"
      >
        {/* Density heatmap bars */}
        {densityBars}

        {/* Viewport indicator */}
        <div
          data-testid="minimap-viewport"
          style={{
            position: 'absolute',
            left: `${viewportLeft}px`,
            top: '4px',
            width: `${viewportWidth}px`,
            height: `${height - 16}px`,
            border: '2px solid var(--pt-intent-primary, #2965cc)',
            backgroundColor: 'rgba(41, 101, 204, 0.15)',
            borderRadius: '2px',
            pointerEvents: 'none',
            transition: 'left 0.15s ease-out, width 0.15s ease-out',
          }}
        />

        {/* Year markers */}
        {yearMarkers}
      </div>
    </Card>
  );
}

export default Minimap;

