     1→/**
     2→ * Canvas Layer Types
     3→ *
     4→ * Type definitions for deck.gl and Konva canvas layers.
     5→ * Aligns with API responses from /canvas/* endpoints.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.3
     8→ */
     9→
    10→// =============================================================================
    11→// Strategic View Types (deck.gl)
    12→// =============================================================================
    13→
    14→/** Yearly PM aggregate for heatmap display */
    15→export interface StrategicYearData {
    16→  year: number;
    17→  pmCount: number;
    18→  totalHours: number;
    19→  completedCount: number;
    20→  lockedCount: number;
    21→}
    22→
    23→/** Train data with yearly PM aggregates */
    24→export interface StrategicTrainData {
    25→  trainId: string;
    26→  trainNumber: string;
    27→  fleetCode: string;
    28→  years: StrategicYearData[];
    29→}
    30→
    31→/** Strategic API response */
    32→export interface StrategicCanvasData {
    33→  trains: StrategicTrainData[];
    34→  heatmapData: {
    35→    maxPmCount: number;
    36→    maxHours: number;
    37→  };
    38→}
    39→
    40→/** Heatmap cell for deck.gl layer */
    41→export interface HeatmapCell {
    42→  trainId: string;
    43→  trainNumber: string;
    44→  trainIndex: number;
    45→  year: number;
    46→  yearIndex: number;
    47→  pmCount: number;
    48→  totalHours: number;
    49→  completedCount: number;
    50→  lockedCount: number;
    51→  intensity: number;
    52→  position: [number, number];
    53→}
    54→
    55→// =============================================================================
    56→// Tactical-Wide View Types (deck.gl)
    57→// =============================================================================
    58→
    59→/** Train data with fleet info for tactical-wide view */
    60→export interface TacticalWideTrainData {
    61→  trainId: string;
    62→  trainNumber: string;
    63→  fleetCode: string;
    64→}
    65→
    66→/** PM block for tactical-wide compressed Gantt display */
    67→export interface TacticalWidePmBlock {
    68→  pmId: string;
    69→  trainId: string;
    70→  pmCode: string;
    71→  targetDate: string;
    72→  durationDays: number;
    73→  status: string;
    74→  isLocked: boolean;
    75→  displayColor: string;
    76→}
    77→
    78→/** Tactical-Wide API response */
    79→export interface TacticalWideCanvasData {
    80→  trains: TacticalWideTrainData[];
    81→  pmBlocks: TacticalWidePmBlock[];
    82→}
    83→
    84→/** Tactical-Wide layer props */
    85→export interface TacticalWideLayerProps extends BaseLayerProps {
    86→  data: TacticalWideCanvasData | null;
    87→  fromDate: Date;
    88→  toDate: Date;
    89→  selectedPmIds?: string[];
    90→  onBlockClick?: (pmId: string) => void;
    91→  onMonthClick?: (month: number, year: number) => void;
    92→}
    93→
    94→// =============================================================================
    95→// Tactical View Types (Konva)
    96→// =============================================================================
    97→
    98→/** PM block for Gantt chart display */
    99→export interface PmBlock {
   100→  pmId: string;
   101→  trainId: string;
   102→  trainNumber: string;
   103→  pmCode: string;
   104→  targetDate: string;
   105→  durationDays: number;
   106→  status: string;
   107→  constraintStart: string;
   108→  constraintEnd: string;
   109→  isLocked: boolean;
   110→  trackNumber: string | null;
   111→  depotCode: string | null;
   112→  displayColor: string;
   113→  estimatedHours: number | null;
   114→}
   115→
   116→/** Constraint wall (compliance window boundary) */
   117→export interface ConstraintWall {
   118→  pmId: string;
   119→  type: 'COMPLIANCE_START' | 'COMPLIANCE_END';
   120→  date: string;
   121→}
   122→
   123→/** Tactical API response */
   124→export interface TacticalCanvasData {
   125→  pmBlocks: PmBlock[];
   126→  constraintWalls: ConstraintWall[];
   127→}
   128→
   129→// =============================================================================
   130→// Overlay Types
   131→// =============================================================================
   132→
   133→/** Man-hour utilization status */
   134→export type ManhourStatus = 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
   135→
   136→/** Depot man-hour data for a week */
   137→export interface DepotManhourData {
   138→  depotId: string;
   139→  depotCode: string;
   140→  requiredHours: number;
   141→  availableHours: number;
   142→  utilizationPct: number;
   143→  status: ManhourStatus;
   144→  adjustments: Array<{
   145→    type: string;
   146→    hours: number;
   147→    status: string;
   148→  }>;
   149→}
   150→
   151→/** Weekly man-hour data */
   152→export interface ManhourWeekData {
   153→  weekStart: string;
   154→  depots: DepotManhourData[];
   155→}
   156→
   157→/** Man-hour overlay API response */
   158→export interface ManhourOverlayData {
   159→  weeks: ManhourWeekData[];
   160→}
   161→
   162→/** Drift severity level */
   163→export type DriftSeverity = 'GREEN' | 'YELLOW' | 'RED';
   164→
   165→/** Train drift data */
   166→export interface TrainDriftData {
   167→  trainId: string;
   168→  trainNumber: string;
   169→  driftSeverity: DriftSeverity;
   170→  mileageDriftPct: number;
   171→  pmDrifts: Array<{
   172→    pmId: string;
   173→    driftDays: number;
