/**
 * Canvas Layer Types
 *
 * Type definitions for deck.gl and Konva canvas layers.
 * Aligns with API responses from /canvas/* endpoints.
 *
 * @see specs/006-user-interface.md Section 6.3
 */

// =============================================================================
// Strategic View Types (deck.gl)
// =============================================================================

/** Yearly PM aggregate for heatmap display */
export interface StrategicYearData {
  year: number;
  pmCount: number;
  totalHours: number;
  completedCount: number;
  lockedCount: number;
}

/** Train data with yearly PM aggregates */
export interface StrategicTrainData {
  trainId: string;
  trainNumber: string;
  fleetCode: string;
  years: StrategicYearData[];
}

/** Strategic API response */
export interface StrategicCanvasData {
  trains: StrategicTrainData[];
  heatmapData: {
    maxPmCount: number;
    maxHours: number;
  };
}

/** Heatmap cell for deck.gl layer */
export interface HeatmapCell {
  trainId: string;
  trainNumber: string;
  trainIndex: number;
  year: number;
  yearIndex: number;
  pmCount: number;
  totalHours: number;
  completedCount: number;
  lockedCount: number;
  intensity: number;
  position: [number, number];
}

// =============================================================================
// Tactical-Wide View Types (deck.gl)
// =============================================================================

/** Train data with fleet info for tactical-wide view */
export interface TacticalWideTrainData {
  trainId: string;
  trainNumber: string;
  fleetCode: string;
}

/** PM block for tactical-wide compressed Gantt display */
export interface TacticalWidePmBlock {
  pmId: string;
  trainId: string;
  pmCode: string;
  targetDate: string;
  durationDays: number;
  status: string;
  isLocked: boolean;
  displayColor: string;
}

/** Tactical-Wide API response */
export interface TacticalWideCanvasData {
  trains: TacticalWideTrainData[];
  pmBlocks: TacticalWidePmBlock[];
}

/** Tactical-Wide layer props */
export interface TacticalWideLayerProps extends BaseLayerProps {
  data: TacticalWideCanvasData | null;
  fromDate: Date;
  toDate: Date;
  selectedPmIds?: string[];
  onBlockClick?: (pmId: string) => void;
  onMonthClick?: (month: number, year: number) => void;
}

// =============================================================================
// Tactical View Types (Konva)
// =============================================================================

/** PM block for Gantt chart display */
export interface PmBlock {
  pmId: string;
  trainId: string;
  trainNumber: string;
  pmCode: string;
  targetDate: string;
  durationDays: number;
  status: string;
  constraintStart: string;
  constraintEnd: string;
  isLocked: boolean;
  trackNumber: string | null;
  depotCode: string | null;
  displayColor: string;
  estimatedHours: number | null;
}

/** Constraint wall (compliance window boundary) */
export interface ConstraintWall {
  pmId: string;
  type: 'COMPLIANCE_START' | 'COMPLIANCE_END';
  date: string;
}

/** Tactical API response */
export interface TacticalCanvasData {
  pmBlocks: PmBlock[];
  constraintWalls: ConstraintWall[];
}

// =============================================================================
// Overlay Types
// =============================================================================

/** Man-hour utilization status */
export type ManhourStatus = 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';

/** Depot man-hour data for a week */
export interface DepotManhourData {
  depotId: string;
  depotCode: string;
  requiredHours: number;
  availableHours: number;
  utilizationPct: number;
  status: ManhourStatus;
  adjustments: Array<{
    type: string;
    hours: number;
    status: string;
  }>;
}

/** Weekly man-hour data */
export interface ManhourWeekData {
  weekStart: string;
  depots: DepotManhourData[];
}

/** Man-hour overlay API response */
export interface ManhourOverlayData {
  weeks: ManhourWeekData[];
}

/** Drift severity level */
export type DriftSeverity = 'GREEN' | 'YELLOW' | 'RED';

/** Train drift data */
export interface TrainDriftData {
  trainId: string;
  trainNumber: string;
  driftSeverity: DriftSeverity;
  mileageDriftPct: number;
  pmDrifts: Array<{
    pmId: string;
    driftDays: number;
  }>;
}

/** Drift overlay API response */
export interface DriftOverlayData {
  baselineId: string;
  baselineName: string;
  trains: TrainDriftData[];
}

// =============================================================================
// Layer Props
// =============================================================================

/** Common layer props */
export interface BaseLayerProps {
  visible: boolean;
  onHover?: (info: unknown) => void;
  onClick?: (info: unknown) => void;
}

/** Strategic heatmap layer props */
export interface StrategicHeatmapLayerProps extends BaseLayerProps {
  data: StrategicCanvasData | null;
  fromYear: number;
  toYear: number;
  onYearClick?: (year: number) => void;
}

/** Tactical Gantt layer props */
export interface TacticalGanttLayerProps extends BaseLayerProps {
  data: TacticalCanvasData | null;
  fromDate: string;
  toDate: string;
  onPmClick?: (pmId: string) => void;
  onPmDragStart?: (pmId: string) => void;
  onPmDragEnd?: (pmId: string, newDate: string) => void;
}

// =============================================================================
// Operational Detail View Types (Konva)
// =============================================================================

/** Material availability status */
export type MaterialStatus = 'AVAILABLE' | 'LOW_STOCK' | 'UNAVAILABLE' | 'ARRIVING';

/** Material requirement for PM */
export interface OperationalMaterialRequirement {
  materialId: string;
  materialName: string;
  quantityRequired: number;
  quantityAvailable: number;
  status: MaterialStatus;
  arrivalDate?: string;
}

/** PM card for operational detail view */
export interface OperationalPmBlock {
  pmId: string;
  trainId: string;
  trainNumber: string;
  fleetCode: string;
  pmCode: string;
  pmDescription: string;
  targetDate: string;
  endDate: string;
  durationDays: number;
  status: string;
  constraintStart: string;
  constraintEnd: string;
  isLocked: boolean;
  trackNumber: string | null;
  depotCode: string | null;
  estimatedHours: number | null;
  assignedShift: string | null;
  materials: OperationalMaterialRequirement[];
  displayColor: string;
}

/** Operational canvas API response */
export interface OperationalCanvasData {
  pmBlocks: OperationalPmBlock[];
  dateRange: {
    fromDate: string;
    toDate: string;
  };
}

/** Operational detail layer props */
export interface OperationalDetailLayerProps extends BaseLayerProps {
  data: OperationalCanvasData | null;
  fromDate: Date;
  toDate: Date;
  width: number;
  height: number;
  selectedPmIds?: string[];
  onPmClick?: (pmId: string) => void;
  onPmHover?: (pm: OperationalPmBlock | null) => void;
  onPmEdit?: (pmId: string) => void;
  onPmLock?: (pmId: string) => void;
}

// =============================================================================
// Drag-and-Drop Types
// =============================================================================

/** Constraint violation during drag operation */
export interface DragConstraintViolation {
  type: 'COMPLIANCE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL' | 'MAXIMO_LOCK' | 'SERVICE_DEMAND';
  severity: 'ERROR' | 'WARNING';
  message: string;
}

/** Drag validation state for real-time feedback */
export interface DragValidationState {
  isValid: boolean;
  message: string | null;
  violations: DragConstraintViolation[];
}

/** Impact assessment for PM move confirmation dialog */
export interface PmMoveImpact {
  manhourChange: {
    sourceWeek: { required: number; available: number };
    targetWeek: { required: number; available: number };
  };
  costChange: number;
  conflictsCreated: string[];
  driftFromBaseline: number;
}

// =============================================================================
// Baseline Shadow Overlay Types
// =============================================================================

/** Baseline PM position for shadow layer display */
export interface BaselinePmBlock {
  pmId: string;
  trainId: string;
  trainNumber: string;
  pmCode: string;
  baselineDate: string;
  currentDate: string | null;
  driftDays: number;
  status: 'UNCHANGED' | 'MOVED' | 'ADDED' | 'REMOVED';
  displayColor: string;
}

/** Baseline shadow overlay API response */
export interface BaselineShadowData {
  baselineId: string;
  baselineName: string;
  baselineDate: string;
  pmBlocks: BaselinePmBlock[];
  summary: {
    totalPms: number;
    movedPms: number;
    addedPms: number;
    removedPms: number;
    unchangedPms: number;
    avgDriftDays: number;
  };
}

