   394→  const handlePmDragStart = (pmId: string, sourceDate: string) => {
   395→    // Find PM in tactical data
   396→    const pm = tacticalData?.pmBlocks.find(p => p.pmId === pmId);
   397→    if (!pm) return;
   398→
   399→    // Store drag info
   400→    draggingPmRef.current = {
   401→      pmId,
   402→      pmCode: pm.pmCode,
   403→      trainId: pm.trainId,
   404→      trainNumber: pm.trainNumber,
   405→      sourceDate,
   406→      constraintStart: pm.constraintStart,
   407→      constraintEnd: pm.constraintEnd,
   408→      isLocked: pm.isLocked,
   409→    };
   410→
   411→    // Initialize drag state in PM slice
   412→    pmActions.startDrag({ pmId, sourceDate });
   413→
   414→    // Set initial validation (quick check)
   415→    const quickResult = quickValidatePmMove({
   416→      pmId,
   417→      currentDate: sourceDate,
   418→      targetDate: sourceDate,
   419→      trainId: pm.trainId,
   420→      constraintStart: pm.constraintStart,
   421→      constraintEnd: pm.constraintEnd,
   422→      isLocked: pm.isLocked,
   423→    });
   424→    dragValidationRef.current = quickResult;
   425→    pmActions.setDragValidation({
   426→      isValid: quickResult.isValid,
   427→      message: quickResult.message,
   428→      violations: quickResult.violations,
   429→    });
   430→  };
   431→
   432→  const handlePmDragMove = (pmId: string, targetDate: string) => {
   433→    const dragInfo = draggingPmRef.current;
   434→    if (!dragInfo || dragInfo.pmId !== pmId) return;
   435→
   436→    // Update target date in PM slice
   437→    pmActions.updateDragTarget(targetDate);
   438→
   439→    // Quick client-side validation
   440→    const quickResult = quickValidatePmMove({
   441→      pmId,
   442→      currentDate: dragInfo.sourceDate,
   443→      targetDate,
   444→      trainId: dragInfo.trainId,
   445→      constraintStart: dragInfo.constraintStart,
   446→      constraintEnd: dragInfo.constraintEnd,
   447→      isLocked: dragInfo.isLocked,
   448→    });
   449→    dragValidationRef.current = quickResult;
   450→    pmActions.setDragValidation({
   451→      isValid: quickResult.isValid,
   452→      message: quickResult.message,
   453→      violations: quickResult.violations,
   454→    });
   455→
   456→    // If quick validation passes, trigger debounced API validation
   457→    if (quickResult.isValid && targetDate !== dragInfo.sourceDate) {
   458→      debouncedValidationRef.current.validate({
   459→        pmId,
   460→        currentDate: dragInfo.sourceDate,
   461→        targetDate,
   462→        trainId: dragInfo.trainId,
   463→      });
   464→    }
   465→  };
   466→
   467→  const handlePmDragEnd = async (pmId: string, targetDate: string) => {
   468→    const dragInfo = draggingPmRef.current;
   469→    if (!dragInfo || dragInfo.pmId !== pmId) {
   470→      // Clear drag state
   471→      pmActions.cancelDrag();
   472→      draggingPmRef.current = null;
   473→      return;
   474→    }
   475→
   476→    // Cancel pending validation
   477→    debouncedValidationRef.current.cancel();
   478→
   479→    // If no change, just cancel
   480→    if (targetDate === dragInfo.sourceDate) {
   481→      pmActions.cancelDrag();
   482→      draggingPmRef.current = null;
   483→      return;
   484→    }
   485→
   486→    // Final quick validation
   487→    const finalValidation = quickValidatePmMove({
   488→      pmId,
   489→      currentDate: dragInfo.sourceDate,
   490→      targetDate,
   491→      trainId: dragInfo.trainId,
   492→      constraintStart: dragInfo.constraintStart,
   493→      constraintEnd: dragInfo.constraintEnd,
   494→      isLocked: dragInfo.isLocked,
   495→    });
   496→
   497→    // If invalid, snap back and show toast
   498→    if (!finalValidation.isValid) {
   499→      pmActions.cancelDrag();
   500→      draggingPmRef.current = null;
   501→      void showToast({
   502→        intent: Intent.DANGER,
   503→        icon: 'error',
   504→        message: finalValidation.message || 'Cannot reschedule: constraint violation',
   505→        timeout: 5000,
   506→      });
   507→      return;
   508→    }
   509→
   510→    // Open confirmation dialog
   511→    dragConfirmRef.current = {
   512→      isOpen: true,
   513→      pmId,
   514→      pmCode: dragInfo.pmCode,
   515→      trainNumber: dragInfo.trainNumber,
   516→      sourceDate: dragInfo.sourceDate,
   517→      targetDate,
   518→      impact: null,
   519→      isLoadingImpact: true,
   520→    };
   521→    // Force re-render by ending drag with commit=false (optimistic update)
   522→    pmActions.endDrag(false);
   523→
   524→    // Load impact assessment
   525→    try {
   526→      const impact = await getPmMoveImpact({
   527→        pmId,
   528→        currentDate: dragInfo.sourceDate,
   529→        targetDate,
   530→        trainId: dragInfo.trainId,
   531→      });
   532→      dragConfirmRef.current = {
   533→        ...dragConfirmRef.current,
   534→        impact,
   535→        isLoadingImpact: false,
   536→      };
   537→    } catch {
   538→      dragConfirmRef.current = {
   539→        ...dragConfirmRef.current,
   540→        isLoadingImpact: false,
   541→      };
   542→    }
   543→
   544→    // Keep draggingPmRef for the confirmation dialog
   545→  };
   546→
   547→  const handleDragConfirm = async () => {
   548→    const confirmState = dragConfirmRef.current;
   549→    const dragInfo = draggingPmRef.current;
   550→
   551→    if (!confirmState.pmId || !dragInfo) {
   552→      handleDragCancel();
   553→      return;
   554→    }
   555→
   556→    try {
   557→      // Commit the move to API
   558→      await commitPmMove({
   559→        pmId: confirmState.pmId,
   560→        currentDate: confirmState.sourceDate,
   561→        targetDate: confirmState.targetDate,
   562→        trainId: dragInfo.trainId,
   563→        reason: 'Manual reschedule via canvas drag-and-drop',
   564→      });
   565→
   566→      // Confirm move in PM slice (updates local state)
   567→      pmActions.confirmMove(confirmState.pmId);
   568→
   569→      // Show success toast
   570→      void showToast({
   571→        intent: Intent.SUCCESS,
   572→        icon: 'tick',
   573→        message: `${confirmState.pmCode} rescheduled to ${confirmState.targetDate}`,
   574→        timeout: 3000,
   575→      });
   576→
   577→      // Reload tactical data to reflect changes
   578→      handleLoadTacticalData();
   579→    } catch (error) {
   580→      // Reject move (revert to original date)
   581→      pmActions.rejectMove(confirmState.pmId);
   582→
   583→      // Show error toast
   584→      void showToast({
   585→        intent: Intent.DANGER,
   586→        icon: 'error',
   587→        message: error instanceof Error ? error.message : 'Failed to reschedule PM',
   588→        timeout: 5000,
   589→      });
   590→    } finally {
   591→      // Close dialog and clear state
   592→      dragConfirmRef.current = initialDragConfirmState;
   593→      draggingPmRef.current = null;
   594→    }
   595→  };
   596→
   597→  const handleDragCancel = () => {
